mapper.select:
SELECT p.fxtm_pbls_data_oid, p.fxtm_pbls_data_ttl, p.aut, p.page_num, p.pblcn_dt, p.cvr_img1_oid, p.cvr_img2_oid, p.open_yn, p.use_yn, p.inq_cnt, p.sort_seq, p.reg_id, p.reg_dt, p.mdfcn_id, p.mdfcn_dt FROM ${schema}.fxtm_pbls_data p
p.use_yn = 'Y'
AND p.fxtm_pbls_data_ttl LIKE CONCAT('%', #{searchKeyword}, '%')
AND p.open_yn = #{openYn}
AND p.pblcn_dt BETWEEN #{bgngDt} AND #{endDt}

SELECT p.fxtm_pbls_data_oid, p.fxtm_pbls_data_ttl, p.pblcn_dt, p.open_yn, p.inq_cnt FROM ${schema}.fxtm_pbls_data p
p.use_yn = 'Y'
AND p.fxtm_pbls_data_ttl LIKE CONCAT('%', #{searchKeyword}, '%')
AND p.open_yn = #{openYn}
AND p.pblcn_dt BETWEEN #{bgngDt} AND #{endDt}

mapper.update:
UPDATE ${schema}.fxtm_pbls_data
SET inq_cnt = inq_cnt + 1
WHERE fxtm_pbls_data_oid = #{fxtmPblsDataOid}
